def _extract_assets():
    mapping = [
        (_TMPL_PATH,   _ASSET_TMPL),
        (_NOTO_R_PATH, _ASSET_NOTO_R),
        (_NOTO_B_PATH, _ASSET_NOTO_B),
        (_CAIRO_R_PATH,_ASSET_CAIRO_R),
        (_CAIRO_B_PATH,_ASSET_CAIRO_B),
    ]
    for path, b64_data in mapping:
        if not os.path.exists(path):
            os.makedirs(os.path.dirname(path), exist_ok=True)
            with open(path, "wb") as f:
                f.write(base64.b64decode(b64_data))
            logger.info(f"✅ استُخرج: {path}")


