def init_db():
    with sqlite3.connect(DB_PATH) as c:
        c.executescript("""
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            telegram_id INTEGER UNIQUE, username TEXT DEFAULT '',
            full_name TEXT DEFAULT '', balance REAL DEFAULT 0,
            is_admin INTEGER DEFAULT 0, is_banned INTEGER DEFAULT 0,
            created_at TEXT DEFAULT CURRENT_TIMESTAMP);
        CREATE TABLE IF NOT EXISTS hospitals (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            name TEXT NOT NULL, name_ar TEXT DEFAULT '',
            city TEXT DEFAULT '', license_number TEXT DEFAULT '',
            logo_path TEXT DEFAULT '', is_active INTEGER DEFAULT 1);
        CREATE TABLE IF NOT EXISTS doctors (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            hospital_id INTEGER, name TEXT NOT NULL,
            name_ar TEXT DEFAULT '', is_active INTEGER DEFAULT 1);
        CREATE TABLE IF NOT EXISTS reports (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            report_number TEXT UNIQUE, user_id INTEGER,
            patient_name TEXT DEFAULT '', patient_id TEXT DEFAULT '',
            birth_date TEXT DEFAULT '', phone TEXT DEFAULT '',
            nationality TEXT DEFAULT '', employer TEXT DEFAULT '',
            city TEXT DEFAULT '', leave_date TEXT DEFAULT '',
            days INTEGER DEFAULT 1, doctor_name TEXT DEFAULT '',
            hospital_name TEXT DEFAULT '', hospital_id INTEGER,
            pdf_path TEXT DEFAULT '', qr_path TEXT DEFAULT '',
            created_at TEXT DEFAULT CURRENT_TIMESTAMP);
        CREATE TABLE IF NOT EXISTS charge_codes (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            code TEXT UNIQUE, amount REAL, is_used INTEGER DEFAULT 0,
            used_by INTEGER, used_at TEXT,
            created_at TEXT DEFAULT CURRENT_TIMESTAMP);
        CREATE TABLE IF NOT EXISTS settings (key TEXT PRIMARY KEY, value TEXT DEFAULT '');
        INSERT OR IGNORE INTO settings VALUES ('report_price','10');
        INSERT OR IGNORE INTO settings VALUES ('report_counter','0');
        INSERT OR IGNORE INTO settings VALUES ('support_whatsapp','966501234567');
        INSERT OR IGNORE INTO settings VALUES ('bot_maintenance','0');
        INSERT OR IGNORE INTO settings VALUES ('web_url','https://seha.sa');
        INSERT OR IGNORE INTO settings VALUES ('hospitals_seeded','0');
        INSERT OR IGNORE INTO settings VALUES ('font_custom_path','');
        """)
    with sqlite3.connect(DB_PATH) as mc:
        try: mc.execute("ALTER TABLE hospitals ADD COLUMN logo_path TEXT DEFAULT ''")
        except: pass
        mc.commit()
    _seed_hospitals()
    _extract_assets()
    _init_arabic_libs()

def _seed_hospitals():
    with sqlite3.connect(DB_PATH) as c:
        c.row_factory = sqlite3.Row
        _row = c.execute("SELECT value FROM settings WHERE key='hospitals_seeded'").fetchone()
        if _row and _row["value"] == "1": return
        if c.execute("SELECT COUNT(*) as n FROM hospitals").fetchone()["n"] > 0:
            c.execute("UPDATE settings SET value='1' WHERE key='hospitals_seeded'")
            c.commit(); return
        for name, city, lic in SAUDI_HOSPITALS:
            c.execute("INSERT INTO hospitals (name,name_ar,city,license_number) VALUES (?,?,?,?)",
                      (name,name,city,lic))
        c.execute("UPDATE settings SET value='1' WHERE key='hospitals_seeded'")
        c.commit()
        logger.info(f"✅ {len(SAUDI_HOSPITALS)} مستشفى")

def _db():
    c = sqlite3.connect(DB_PATH); c.row_factory = sqlite3.Row; return c

def gs(key, default=""):
    with _db() as c:
        r = c.execute("SELECT value FROM settings WHERE key=?", (key,)).fetchone()
        return r["value"] if r else default

def ss(key, val):
    with _db() as c:
        c.execute("INSERT OR REPLACE INTO settings VALUES (?,?)", (key,str(val))); c.commit()

def ensure_user(tid, username, full_name):
    with _db() as c:
        c.execute("INSERT OR IGNORE INTO users (telegram_id,username,full_name) VALUES (?,?,?)",
                  (tid, username or "", full_name or "")); c.commit()

def get_user(tid):
    with _db() as c: return c.execute("SELECT * FROM users WHERE telegram_id=?",(tid,)).fetchone()

def get_balance(tid):
    u = get_user(tid); return float(u["balance"]) if u else 0.0

def upd_balance(tid, delta):
    with _db() as c:
        c.execute("UPDATE users SET balance=balance+? WHERE telegram_id=?",(delta,tid)); c.commit()

def is_admin(tid):
    if tid in ADMIN_IDS: return True
    u = get_user(tid); return bool(u and u["is_admin"])

def is_banned(tid):
    u = get_user(tid); return bool(u and u["is_banned"])

def next_rnum():
    n = int(gs("report_counter","0"))+1; ss("report_counter",n)
    return f"GSL{datetime.now().strftime('%y%m%d')}{n:04d}"

def get_hospitals(search=None, city=None):
    with _db() as c:
        if search:
            return c.execute("SELECT * FROM hospitals WHERE is_active=1 AND (name LIKE ? OR name_ar LIKE ?)",
                             (f"%{search}%",f"%{search}%")).fetchall()
        if city:
            return c.execute("SELECT * FROM hospitals WHERE is_active=1 AND city=?",(city,)).fetchall()
        return c.execute("SELECT * FROM hospitals WHERE is_active=1 ORDER BY name").fetchall()

def get_cities():
    with _db() as c:
        return [r["city"] for r in c.execute(
            "SELECT DISTINCT city FROM hospitals WHERE is_active=1 AND city!='' ORDER BY city").fetchall()]

def get_doctors(hid):
    with _db() as c:
        return c.execute("SELECT * FROM doctors WHERE hospital_id=? AND is_active=1",(hid,)).fetchall()


