#  الخطوط والعربية
# ══════════════════════════════════════════════════════════════
_FC = {}
_AR_RESHAPER = None
_AR_BIDI     = None

def _init_arabic_libs():
    global _AR_RESHAPER, _AR_BIDI
    if _AR_RESHAPER is not None: return
    try:
        import arabic_reshaper
        _AR_RESHAPER = arabic_reshaper
        logger.info("✅ arabic_reshaper")
    except ImportError:
        _AR_RESHAPER = False
        logger.warning("⚠️ pip install arabic-reshaper")
    try:
        from bidi.algorithm import get_display
        _AR_BIDI = get_display
        logger.info("✅ python-bidi")
    except ImportError:
        _AR_BIDI = False
        logger.warning("⚠️ pip install python-bidi")

def _fnt(size, bold=False):
    custom = gs("font_custom_path","")
    key = (custom, size, bold)
    if key in _FC: return _FC[key]
    paths = []
    if custom and os.path.exists(custom): paths.append(custom)
    if bold:
        paths += [_NOTO_B_PATH, _CAIRO_B_PATH,
                  "/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf"]
    else:
        paths += [_NOTO_R_PATH, _CAIRO_R_PATH,
                  "/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf"]
    for p in paths:
        if p and os.path.exists(p):
            try:
                f = ImageFont.truetype(p, size); _FC[key]=f; return f
            except: continue
    f = ImageFont.load_default(); _FC[key]=f; return f

def _tw(draw, text, font):
    try: b=draw.textbbox((0,0),text,font=font); return b[2]-b[0]
    except: return len(text)*10

def _th(draw, text, font):
    try: b=draw.textbbox((0,0),text,font=font); return b[3]-b[1]
    except: return getattr(font,"size",20)

def _dc(draw, text, px, py, font, color):
    """رسم نص مركز"""
    w,h = _tw(draw,text,font), _th(draw,text,font)
    draw.text((px-w//2, py-h//2), text, font=font, fill=color)

def _dr(draw, text, rx, py, font, color):
    """رسم نص محاذٍ لليمين"""
    w,h = _tw(draw,text,font), _th(draw,text,font)
    draw.text((rx-w, py-h//2), text, font=font, fill=color)

def _dl(draw, text, lx, py, font, color):
    """رسم نص محاذٍ لليسار"""
    h = _th(draw,text,font)
    draw.text((lx, py-h//2), text, font=font, fill=color)

def _fit(draw, text, max_w, fs, bold=False):
    f = _fnt(fs, bold)
    while _tw(draw,text,f) > max_w and fs > 12:
        fs -= 2; f = _fnt(fs, bold)
    return f

def _ar(text):
    """معالجة النص العربي — RTL + اتصال الحروف"""
    if not text: return text
    if not any("\u0600"<=c<="\u06FF" for c in text): return text
    _init_arabic_libs()
    try:
        if _AR_RESHAPER and _AR_BIDI:
            return _AR_BIDI(_AR_RESHAPER.reshape(text))
        if _AR_BIDI:
            return _AR_BIDI(text)
    except: pass
    # fallback: لا عكس — اعرض كما هو
    return text

def _is_arabic(text):
    """هل النص يحتوي على عربية؟"""
    return any("\u0600"<=c<="\u06FF" for c in (text or ""))

def _latin_only(text):
    """أعد النص فقط إذا كان لاتيني — وإلا أعد string فارغ"""
    if not text: return ""
    return "" if _is_arabic(text) else text

