# جدول transliteration عربي→لاتيني
_TRANS_TABLE = {
    "ا":"A","أ":"A","إ":"I","آ":"AA","ء":"","ئ":"Y","ؤ":"W",
    "ب":"B","ت":"T","ث":"TH","ج":"J","ح":"H","خ":"KH",
    "د":"D","ذ":"TH","ر":"R","ز":"Z","س":"S","ش":"SH",
    "ص":"S","ض":"D","ط":"T","ظ":"TH","ع":"A","غ":"GH",
    "ف":"F","ق":"Q","ك":"K","ل":"L","م":"M","ن":"N",
    "ه":"H","و":"W","ي":"Y","ى":"A","ة":"H","ه":"H",
    "َ":"A","ُ":"U","ِ":"I","ّ":"","ْ":"","ً":"","ٌ":"","ٍ":"",
    " ":" ",
}

def _transliterate(text: str) -> str:
    """تحويل عربي→لاتيني حرف بحرف (بدون إنترنت)"""
    if not text: return ""
    result = []
    for ch in text:
        result.append(_TRANS_TABLE.get(ch, ch))
    return "".join(result).upper().strip()

_DEEP_TR = None
_DEEP_OK = None

def _try_deep_translate(text: str) -> str:
    """محاولة ترجمة عبر deep_translator — مع fallback للـ transliteration"""
    global _DEEP_TR, _DEEP_OK
    # إذا سبق وفشل، لا تحاول مجدداً
    if _DEEP_OK is False:
        return _transliterate(text)
    try:
        if _DEEP_TR is None:
            from deep_translator import GoogleTranslator
            _DEEP_TR = GoogleTranslator(source="ar", target="en")
            _DEEP_OK = True
        result = _DEEP_TR.translate(text)
        if result and len(result) > 1:
            return result.strip().upper()
    except Exception as e:
        _DEEP_OK = False
        logger.warning(f"deep_translator failed, using transliteration: {e}")
    return _transliterate(text)

def _translate_ar_to_en(text: str) -> str:
    """
    يترجم أي نص عربي إلى إنجليزي.
    الطبقات:
      1. نص إنجليزي → .upper() مباشرة
      2. جدول الجنسيات → دقة 100%
      3. deep_translator → Google Translate
      4. transliteration → حرف بحرف (لا يفشل أبداً)
    """
    if not text: return ""
    text = text.strip()
    if not _is_arabic(text):
        return text.upper()
    # جدول الجنسيات
    if text in _NAT_TABLE:
        return _NAT_TABLE[text]
    # deep_translator أو transliteration
    return _try_deep_translate(text)

async def _translate_async(text: str) -> str:
    """ترجمة async في thread — لا تحجب البوت"""
    if not text: return ""
    if not _is_arabic(text): return text.upper()
    loop = asyncio.get_running_loop()
    return await loop.run_in_executor(_EXECUTOR, _translate_ar_to_en, text)

# ══════════════════════════════════════════════════════════════
#  حساب التاريخ ومدة الإجازة
# ══════════════════════════════════════════════════════════════
def _dur(leave_date, days):
    try:
        nd = max(1,int(str(days))) if str(days).isdigit() else 1
        s  = datetime.strptime(leave_date,"%d-%m-%Y")
        e  = s + timedelta(days=nd-1)
        es,ee = s.strftime("%d-%m-%Y"), e.strftime("%d-%m-%Y")
        w_en = "day" if nd==1 else "days"
        w_ar = "\u064a\u0648\u0645" if nd==1 else "\u0623\u064a\u0627\u0645"
        return (f"{nd} {w_en} ( {es} to {ee} )",
                f"{nd} {w_ar} ({es} \u0627\u0644\u0649 {ee})", es, ee)
    except:
        return str(days), str(days), leave_date, leave_date

# ══════════════════════════════════════════════════════════════
#  QR Code
# ══════════════════════════════════════════════════════════════
def _make_qr_sync(rnum, verify_url):
    if not HAS_QR: return ""
    try:
        qr = qrcode.QRCode(version=3,
                           error_correction=qrcode.constants.ERROR_CORRECT_M,
                           box_size=10, border=2)
        qr.add_data(verify_url); qr.make(fit=True)
        qi = qr.make_image(fill_color="black", back_color="white")
        path = os.path.join(QR_DIR, f"{rnum}.png"); qi.save(path)
        return path
    except Exception as e:
        logger.warning(f"QR: {e}"); return ""

async def make_qr(rnum, verify_url):
    loop = asyncio.get_running_loop()
    return await loop.run_in_executor(_EXECUTOR, _make_qr_sync, rnum, verify_url)

# ══════════════════════════════════════════════════════════════
#  القالب + شعار
