def _get_template():
    if not os.path.exists(_TMPL_PATH):
        _extract_assets()
    return Image.open(_TMPL_PATH).convert("RGB")

def _paste_logo_sync(img, logo_path):
    if not logo_path or not os.path.exists(logo_path): return img
    try:
        iw,ih = img.size
        def cx(v): return int(v*iw/TW)
        def cy(v): return int(v*ih/TH)
        lx1=cx(LOGO_X1); ly1=cy(LOGO_Y1); lx2=cx(LOGO_X2); ly2=cy(LOGO_Y2)
        bw,bh = lx2-lx1, ly2-ly1
        logo = Image.open(logo_path).convert("RGBA")
        lw,lh = logo.size
        sc = min(bw/lw, bh/lh, 1.0)
        nw,nh = int(lw*sc), int(lh*sc)
        logo = logo.resize((nw,nh), Image.LANCZOS)
        ox = lx1+(bw-nw)//2; oy = ly1+(bh-nh)//2
        bg = Image.new("RGBA", img.size, (0,0,0,0))
        bg.paste(logo, (ox,oy), logo)
        return Image.alpha_composite(img.convert("RGBA"), bg).convert("RGB")
    except Exception as e:
        logger.warning(f"Logo: {e}"); return img

def _preview_sync(logo_path=""):
    """معاينة خفيفة — أقل استهلاك للذاكرة"""
    # فتح الصورة مباشرة بحجم صغير
    img = Image.open(_TMPL_PATH).convert("RGB")
    # تصغير فوري قبل أي معالجة
    img = img.resize((600, 849), Image.LANCZOS)
    iw, ih = img.size
    if logo_path and os.path.exists(logo_path):
        try:
            lx1=int(LOGO_X1*iw/TW); ly1=int(LOGO_Y1*ih/TH)
            lx2=int(LOGO_X2*iw/TW); ly2=int(LOGO_Y2*ih/TH)
            bw,bh=lx2-lx1, ly2-ly1
            logo=Image.open(logo_path).convert("RGBA")
            lw,lh=logo.size; sc=min(bw/lw,bh/lh,1.0)
            logo=logo.resize((int(lw*sc),int(lh*sc)),Image.LANCZOS)
            ox=lx1+(bw-logo.width)//2; oy=ly1+(bh-logo.height)//2
            bg=Image.new("RGBA",img.size,(0,0,0,0))
            bg.paste(logo,(ox,oy),logo)
            img=Image.alpha_composite(img.convert("RGBA"),bg).convert("RGB")
        except Exception as e:
            logger.warning(f"Preview: {e}")
    buf=BytesIO(); img.save(buf,"JPEG",quality=75); buf.seek(0)
    return buf

async def preview_async(logo_path=""):
    loop = asyncio.get_running_loop()
    return await loop.run_in_executor(_EXECUTOR, _preview_sync, logo_path)

# ══════════════════════════════════════════════════════════════
#  ✅ create_pdf — الدالة الرئيسية
# ══════════════════════════════════════════════════════════════
def _create_pdf_sync(rnum, data):
    now  = datetime.now()
    ld   = data.get("leave_date", now.strftime("%d-%m-%Y"))
    days = data.get("days","1")
    dur_en, dur_ar, adm, dis = _dur(ld, days)

    img = _get_template()
    img = _paste_logo_sync(img, data.get("logo_path",""))
    iw, ih = img.size

    # scale helpers
    def cx(v): return int(v*iw/TW)
    def cy(v): return int(v*ih/TH)
    def cw(v): return max(1, int(v*iw/TW))
    def cfs(v): return max(8, int(v*iw/TW))

    draw = ImageDraw.Draw(img)

    # خطوط
    fv   = _fnt(cfs(FS_V))
    fvb  = _fnt(cfs(FS_VB),  bold=True)
    fs_  = _fnt(cfs(FS_S))
    fft  = _fnt(cfs(FS_FT),  bold=True)
    fvr  = _fnt(cfs(FS_VR))
    furl = _fnt(cfs(FS_URL))

    # حدود الأعمدة (scaled)
    col1=cx(COL1); col2=cx(COL2); col3=cx(COL3)
    cx_en=cx(CX_EN); cx_ar=cx(CX_AR); cx_full=cx(CX_FULL)
    cell_en=col2-col1-cw(20); cell_ar=col3-col2-cw(20); cell_fu=col3-col1-cw(30)

    # النصوص
    name_en  = data.get("patient_name_en", data.get("patient_name","").upper())
    nat_en   = data.get("nationality_en", "")
    doc_en   = data.get("doctor_name_en",  data.get("doctor_name","").upper())
    pos_en   = data.get("position_en","General")
    hosp_en  = data.get("hospital_name_en", data.get("hospital_name","").upper())
    pat_id   = data.get("patient_id","")
    vurl     = data.get("verify_url", f"{gs('web_url','https://seha.sa')}/#/inquiries/slenquiry")

    name_ar  = _ar(data.get("patient_name",""))
    nat_ar   = _ar(data.get("nationality",""))
    emp_ar   = _ar(data.get("employer",""))
    doc_ar   = _ar(data.get("doctor_name",""))
    pos_ar   = _ar(data.get("position_ar","\u0637\u0628\u064a\u0628 \u0639\u0627\u0645"))
    hosp_ar  = _ar(data.get("hospital_name",""))
    dur_ar_r = _ar(dur_ar)

    # ── رسم الجدول ──

    # ① Leave ID
    fi = _fit(draw, rnum, cell_fu, cfs(FS_VB), bold=True)
    _dc(draw, rnum, cx_full, cy(ROW_CY["leave_id"]), fi, C_BLUE)

    # ② Duration (أبيض على داكن)
    fde = _fit(draw, dur_en,   cell_en, cfs(FS_S))
    fda = _fit(draw, dur_ar_r, cell_ar, cfs(FS_S))
    _dc(draw, dur_en,   cx_en, cy(ROW_CY["leave_dur"]), fde, C_WHITE)
    _dc(draw, dur_ar_r, cx_ar, cy(ROW_CY["leave_dur"]), fda, C_WHITE)

    # ③ Admission
    _dc(draw, adm, cx_en, cy(ROW_CY["admission"]), fv, C_BLUE)
    _dc(draw, adm, cx_ar, cy(ROW_CY["admission"]), fv, C_BLUE)

    # ④ Discharge
    _dc(draw, dis, cx_en, cy(ROW_CY["discharge"]), fv, C_BLUE)
    _dc(draw, dis, cx_ar, cy(ROW_CY["discharge"]), fv, C_BLUE)

    # ⑤ Issue Date
    _dc(draw, now.strftime("%d-%m-%Y"), cx_full, cy(ROW_CY["issue_date"]), fvb, C_BLUE)

    # ⑥ Name
    fen = _fit(draw, name_en, cell_en, cfs(FS_VB), bold=True)
    fan = _fit(draw, name_ar, cell_ar, cfs(FS_VB), bold=True)
    _dc(draw, name_en, cx_en, cy(ROW_CY["name"]), fen, C_BLUE)
    _dc(draw, name_ar, cx_ar, cy(ROW_CY["name"]), fan, C_BLUE)

    # ⑦ National ID
    fid = _fit(draw, pat_id, cell_fu, cfs(FS_VB), bold=True)
    _dc(draw, pat_id, cx_full, cy(ROW_CY["national_id"]), fid, C_BLUE)

    # ⑧ Nationality
    _dc(draw, nat_en, cx_en, cy(ROW_CY["nationality"]), fv, C_BLUE)
    _dc(draw, nat_ar, cx_ar, cy(ROW_CY["nationality"]), fv, C_BLUE)

    # ⑨ Employer (AR فقط)
    fem = _fit(draw, emp_ar, cell_ar, cfs(FS_V))
    _dc(draw, emp_ar, cx_ar, cy(ROW_CY["employer"]), fem, C_BLUE)

    # ⑩ Doctor
    fdn  = _fit(draw, doc_en, cell_en, cfs(FS_V))
    fda2 = _fit(draw, doc_ar, cell_ar, cfs(FS_V))
    _dc(draw, doc_en, cx_en, cy(ROW_CY["doctor"]), fdn,  C_BLUE)
    _dc(draw, doc_ar, cx_ar, cy(ROW_CY["doctor"]), fda2, C_BLUE)

    # ⑪ Position
    fpe = _fit(draw, pos_en, cell_en, cfs(FS_V))
    fpa = _fit(draw, pos_ar, cell_ar, cfs(FS_V))
    _dc(draw, pos_en, cx_en, cy(ROW_CY["position"]), fpe, C_BLUE)
    _dc(draw, pos_ar, cx_ar, cy(ROW_CY["position"]), fpa, C_BLUE)

    # ── QR ──
    qp = data.get("qr_path","")
    if qp and os.path.exists(qp):
        try:
            qsz = cx(QR_SIZE)
            qi  = Image.open(qp).convert("RGB").resize((qsz,qsz), Image.LANCZOS)
            img.paste(qi, (cx(QR_X1), cy(QR_Y1)))
            draw = ImageDraw.Draw(img)
        except Exception as e: logger.warning(f"QR: {e}")

    # ── شعار المستشفى + اسمه (فقط إذا وُجد شعار) ──
    logo_path = data.get("logo_path","")
    if logo_path and os.path.exists(logo_path):
        fh  = _fit(draw, hosp_ar, cx(LOGO_X2)-cx(LOGO_X1)+50, cfs(FS_H),  bold=True)
        fhe = _fit(draw, hosp_en, cx(LOGO_X2)-cx(LOGO_X1)+50, cfs(FS_HE))
        _dc(draw, hosp_ar, cx(LOGO_CX), cy(HOSP_AR_CY), fh,  C_DARK)
        _dc(draw, hosp_en, cx(LOGO_CX), cy(HOSP_EN_CY), fhe, C_DARK)

    # ── الخط الأزرق + URL (يمر وسط الخط) ──
    ux1=cx(URL_X1); ux2=cx(URL_X2); uy=cy(URL_LINE_Y)
    draw.line([(ux1,uy),(ux2,uy)], fill=C_LINK, width=cw(3))
    url_txt = vurl[:55] if len(vurl)>55 else vurl
    fu2 = _fit(draw, url_txt, ux2-ux1-10, cfs(FS_URL))
    uw=_tw(draw,url_txt,fu2); uh=_th(draw,url_txt,fu2)
    draw.text((cx(URL_CX)-uw//2, uy-uh//2), url_txt, font=fu2, fill=C_LINK)

    # ── الوقت والتاريخ (محاذيان NHIC) ──
    try:    t_s=now.strftime("%I:%M %p"); d_s=now.strftime("%A, %-d %B %Y")
    except: t_s=now.strftime("%I:%M %p"); d_s=now.strftime("%A, %d %B %Y")
    _dl(draw, t_s, cx(TIME_X), cy(TIME_CY), fft, C_DARK)
    _dl(draw, d_s, cx(TIME_X), cy(DAY_CY),  fft, C_DARK)

    # ── PDF ──
    pdf_out = os.path.join(REPORTS_DIR, f"{rnum}.pdf")
    # حفظ PDF مباشرة بدون ملف مؤقت (توفير ذاكرة)
    buf = BytesIO()
    img.convert("RGB").save(buf, format="PDF", resolution=300)
    buf.seek(0)
    with open(pdf_out, "wb") as f:
        f.write(buf.getvalue())
    del buf, img  # تحرير الذاكرة فوراً
    return pdf_out

async def create_pdf_async(rnum, data):
    loop = asyncio.get_running_loop()
    return await loop.run_in_executor(_EXECUTOR, _create_pdf_sync, rnum, data)


