def KB(tid):
    r = [["📋 إنشاء إجازة جديدة"],
         ["📊 إحصائياتي","🏥 قائمة المستشفيات"],
         ["💰 رصيدي والاشتراك","📞 الدعم عبر واتساب"]]
    if is_admin(tid): r.append(["👨‍💼 لوحة الإدارة"])
    return ReplyKeyboardMarkup(r, resize_keyboard=True)

KB_ADM = ReplyKeyboardMarkup([
    ["➕ إضافة مستشفى",        "➕ إضافة دكتور"],
    ["💳 إنشاء كود شحن",       "🖼️ شعارات المستشفيات"],
    ["🎨 إعدادات الخط",        "📊 الإحصائيات"],
    ["👥 إدارة المستخدمين",    "⚙️ الإعدادات"],
    ["📢 إرسال إعلان",         "📋 سجل الأخطاء"],
    ["🔙 رجوع للرئيسية"],
], resize_keyboard=True)

KB_BACK     = ReplyKeyboardMarkup([["🔙 رجوع"]], resize_keyboard=True)
KB_ADM_BACK = ReplyKeyboardMarkup([["🔙 رجوع للإدارة"]], resize_keyboard=True)

def ik_paged(items, pfx, page=0, per=8, extra=None):
    s=page*per; chunk=items[s:s+per]
    rows=[[InlineKeyboardButton(str(i[1]),callback_data=f"{pfx}_{i[0]}")] for i in chunk]
    nav=[]
    if page>0: nav.append(InlineKeyboardButton("◀️",callback_data=f"{pfx}_pg_{page-1}"))
    if s+per<len(items): nav.append(InlineKeyboardButton("▶️",callback_data=f"{pfx}_pg_{page+1}"))
    if nav: rows.append(nav)
    if extra:
        for b in extra: rows.append([b])
    rows.append([InlineKeyboardButton("🔙 رجوع",callback_data=f"{pfx}_back")])
    return InlineKeyboardMarkup(rows)

def _list_fonts():
    sys_fonts = {
        "DejaVu Sans": "/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf",
        "DejaVu Bold": "/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf",
    }
    fonts = [(n,p) for n,p in sys_fonts.items() if os.path.exists(p)]
    if os.path.exists(FONTS_DIR):
        for fn in os.listdir(FONTS_DIR):
            if fn.lower().endswith(".ttf"):
                fonts.append((f"✨ {fn[:-4]}", os.path.join(FONTS_DIR,fn)))
    return fonts


