async def cmd_start(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    u = update.effective_user; ensure_user(u.id, u.username, u.full_name)
    if is_banned(u.id): await update.message.reply_text("⛔ تم حظر حسابك."); return ST_MAIN
    if gs("bot_maintenance","0")=="1" and not is_admin(u.id):
        await update.message.reply_text("🔧 البوت في وضع الصيانة."); return ST_MAIN
    bal=get_balance(u.id); price=gs("report_price","10")
    await update.message.reply_text(
        f"👋 أهلاً *{u.first_name}*!\n\n🏥 *بوت الإجازات المرضية*\n"
        f"━━━━━━━━━━━━━━━━━━\n💰 رصيدك: *{bal:.2f} ريال*\n"
        f"💊 سعر الإجازة: *{price} ريال*\n\nاختر من القائمة 👇",
        parse_mode="Markdown", reply_markup=KB(u.id))
    ctx.user_data.clear(); return ST_MAIN

async def main_menu(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    u=update.effective_user; t=update.message.text
    if is_banned(u.id): await update.message.reply_text("⛔ حسابك محظور."); return ST_MAIN
    if   t=="📋 إنشاء إجازة جديدة":  return await rpt_start(update,ctx)
    elif t=="📊 إحصائياتي":           return await show_stats(update,ctx)
    elif t=="🏥 قائمة المستشفيات":    return await show_hosp_list(update,ctx)
    elif t=="💰 رصيدي والاشتراك":     return await show_balance(update,ctx)
    elif t=="📞 الدعم عبر واتساب":
        num=gs("support_whatsapp","966501234567")
        await update.message.reply_text(
            f"📞 *للتواصل مع الدعم:*\n\n[اضغط هنا](https://wa.me/{num})",
            parse_mode="Markdown", reply_markup=KB(u.id)); return ST_MAIN
    elif t=="👨‍💼 لوحة الإدارة" and is_admin(u.id):
        await update.message.reply_text("👨‍💼 *لوحة الإدارة*",parse_mode="Markdown",reply_markup=KB_ADM)
        return ST_ADM
    elif t in ["🔙 رجوع","🔙 رجوع للرئيسية","🔙 رجوع للإدارة"]:
        await cmd_start(update,ctx); return ST_MAIN
    return ST_MAIN

async def show_stats(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    u=update.effective_user
    with _db() as c:
        total=c.execute("SELECT COUNT(*) as n FROM reports WHERE user_id=?",(u.id,)).fetchone()["n"]
        last=c.execute("SELECT report_number,leave_date FROM reports WHERE user_id=? ORDER BY id DESC LIMIT 1",(u.id,)).fetchone()
    bal=get_balance(u.id); price=gs("report_price","10")
    txt=(f"📊 *إحصائياتك:*\n━━━━━━━━━━━━━━━━━━\n"
         f"📋 إجمالي الإجازات: *{total}*\n💰 رصيدك: *{bal:.2f} ريال*\n💊 السعر: *{price} ريال*\n")
    if last: txt+=f"\n📌 آخر إجازة: `{last['report_number']}` — {last['leave_date']}"
    await update.message.reply_text(txt,parse_mode="Markdown",reply_markup=KB(u.id))
    return ST_MAIN

async def show_hosp_list(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    hs=get_hospitals()
    if not hs: await update.message.reply_text("🏥 لا توجد مستشفيات.",reply_markup=KB(update.effective_user.id)); return ST_MAIN
    txt="🏥 *المستشفيات:*\n━━━━━━━━━━━━━━━━━━\n"
    for h in hs: txt+=f"▪️ {h['name']}{('  —  '+h['city']) if h['city'] else ''}\n"
    await update.message.reply_text(txt,parse_mode="Markdown",reply_markup=KB(update.effective_user.id))
    return ST_MAIN

async def show_balance(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    u=update.effective_user; bal=get_balance(u.id); price=gs("report_price","10")
    await update.message.reply_text(
        f"💰 *رصيدك:* {bal:.2f} ريال\n💊 تكلفة الإجازة: {price} ريال\n\nأدخل كود الشحن:",
        parse_mode="Markdown",reply_markup=KB_BACK)
    return ST_CHARGE

async def do_charge(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    if update.message.text=="🔙 رجوع": await cmd_start(update,ctx); return ST_MAIN
    u=update.effective_user; code=update.message.text.strip().upper()
    with _db() as c:
        row=c.execute("SELECT * FROM charge_codes WHERE code=? AND is_used=0",(code,)).fetchone()
    if not row: await update.message.reply_text("❌ الكود غير صحيح أو مستخدم."); return ST_CHARGE
    amount=row["amount"]
    with _db() as c:
        c.execute("UPDATE charge_codes SET is_used=1,used_by=?,used_at=? WHERE code=?",
                  (u.id,datetime.now().isoformat(),code)); c.commit()
    upd_balance(u.id,amount)
    await update.message.reply_text(
        f"✅ *تم شحن {amount:.2f} ريال!*\n💰 رصيدك الجديد: *{get_balance(u.id):.2f} ريال*",
        parse_mode="Markdown",reply_markup=KB(u.id))
    return ST_MAIN


