#  إصدار الإجازة
# ══════════════════════════════════════════════════════════════
async def rpt_start(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    u=update.effective_user; price=float(gs("report_price","10")); bal=get_balance(u.id)
    if bal<price:
        await update.message.reply_text(
            f"⚠️ *رصيدك غير كافٍ!*\n💰 رصيدك: {bal:.2f}\n💊 المطلوب: {price:.0f} ريال",
            parse_mode="Markdown"); return ST_MAIN
    ctx.user_data["R"]={}
    await update.message.reply_text("🏥 *اختر طريقة البحث:*",parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup([
            [InlineKeyboardButton("🔍 بحث باسم المستشفى",callback_data="rs_name")],
            [InlineKeyboardButton("📋 عرض كل المستشفيات",callback_data="rs_all")],
            [InlineKeyboardButton("🌆 بحث باسم المدينة", callback_data="rs_city")],
            [InlineKeyboardButton("🔙 رجوع",             callback_data="rs_back")],
        ])); return ST_RPT_SEARCH

async def rpt_search_cb(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    q=update.callback_query; await q.answer(); d=q.data
    if d=="rs_back":
        await q.edit_message_text("🔙"); await q.message.reply_text("🏠",reply_markup=KB(q.from_user.id))
        return ST_MAIN
    if d=="rs_name": await q.edit_message_text("🔍 اكتب اسم المستشفى:"); return ST_RPT_SINPUT
    if d=="rs_all":
        hs=get_hospitals()
        if not hs: await q.edit_message_text("❌ لا توجد مستشفيات."); return ST_MAIN
        items=[(h["id"],f"{h['name']}{'  —  '+h['city'] if h['city'] else ''}") for h in hs]
        await q.edit_message_text("🏥 اختر المستشفى:",reply_markup=ik_paged(items,"H",0)); return ST_RPT_HOSP
    if d=="rs_city":
        cities=get_cities()
        if not cities: await q.edit_message_text("❌ لا توجد مدن."); return ST_MAIN
        btns=[[InlineKeyboardButton(c,callback_data=f"CT_{c}")] for c in cities]
        btns.append([InlineKeyboardButton("🔙 رجوع",callback_data="rs_back")])
        await q.edit_message_text("🌆 اختر المدينة:",reply_markup=InlineKeyboardMarkup(btns)); return ST_RPT_CITY
    if d.startswith("CT_"):
        city=d[3:]; hs=get_hospitals(city=city)
        if not hs: await q.edit_message_text(f"❌ لا توجد مستشفيات في {city}."); return ST_MAIN
        items=[(h["id"],h["name"]) for h in hs]
        await q.edit_message_text(f"🏥 مستشفيات {city}:",reply_markup=ik_paged(items,"H",0)); return ST_RPT_HOSP
    return ST_RPT_SEARCH

async def rpt_sinput(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    if update.message.text=="🔙 رجوع": await cmd_start(update,ctx); return ST_MAIN
    hs=get_hospitals(search=update.message.text.strip())
    if not hs: await update.message.reply_text("❌ لم يتم العثور. اكتب اسماً آخر:"); return ST_RPT_SINPUT
    items=[(h["id"],f"{h['name']}{'  —  '+h['city'] if h['city'] else ''}") for h in hs]
    await update.message.reply_text("🏥 نتائج البحث:",reply_markup=ik_paged(items,"H",0)); return ST_RPT_HOSP

async def rpt_hosp_cb(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    q=update.callback_query; await q.answer(); d=q.data
    if d=="H_back":
        await q.edit_message_text("🏥 *اختر طريقة البحث:*",parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([
                [InlineKeyboardButton("🔍 بحث باسم المستشفى",callback_data="rs_name")],
                [InlineKeyboardButton("📋 عرض كل المستشفيات",callback_data="rs_all")],
                [InlineKeyboardButton("🌆 بحث باسم المدينة", callback_data="rs_city")],
                [InlineKeyboardButton("🔙 رجوع",             callback_data="rs_back")],
            ])); return ST_RPT_SEARCH
    if d.startswith("H_pg_"):
        page=int(d.split("_")[-1]); hs=get_hospitals()
        items=[(h["id"],f"{h['name']}{'  —  '+h['city'] if h['city'] else ''}") for h in hs]
        await q.edit_message_text("🏥 اختر المستشفى:",reply_markup=ik_paged(items,"H",page)); return ST_RPT_HOSP
    if d.startswith("H_"): return await _select_hosp(q,ctx,int(d[2:]))
    return ST_RPT_HOSP

async def _select_hosp(q, ctx, hid):
    with _db() as c: h=c.execute("SELECT * FROM hospitals WHERE id=?",(hid,)).fetchone()
    if not h: await q.edit_message_text("❌ المستشفى غير موجود."); return ST_MAIN
    R=ctx.user_data.setdefault("R",{})
    R.update({"hospital_id":hid,"hospital_name":h["name"],
              "hospital_city":h["city"] or "","logo_path":h["logo_path"] or ""})
    docs=get_doctors(hid)
    btns=[[InlineKeyboardButton(f"👨‍⚕️ {d['name']}",callback_data=f"D_{d['id']}")] for d in docs]
    btns.append([InlineKeyboardButton("✏️ إدخال اسم الدكتور يدوياً",callback_data="D_manual")])
    btns.append([InlineKeyboardButton("🔙 رجوع",callback_data="D_back")])
    await q.edit_message_text(f"🏥 *{h['name']}*\n\n👨‍⚕️ اختر الطبيب:",
                               parse_mode="Markdown",reply_markup=InlineKeyboardMarkup(btns))
    return ST_RPT_DOC

async def rpt_doc_cb(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    q=update.callback_query; await q.answer(); d=q.data
    if d=="D_back":
        hs=get_hospitals(); items=[(h["id"],h["name"]) for h in hs]
        await q.edit_message_text("🏥 اختر المستشفى:",reply_markup=ik_paged(items,"H",0)); return ST_RPT_HOSP
    if d=="D_manual": await q.edit_message_text("✏️ أدخل اسم الطبيب:"); return ST_RPT_DOC_MAN
    if d.startswith("D_"):
        did=int(d[2:])
        with _db() as c: doc=c.execute("SELECT * FROM doctors WHERE id=?",(did,)).fetchone()
        if doc: ctx.user_data["R"]["doctor_name"]=doc["name"]
        return await _send_form(q.message,ctx)
    return ST_RPT_DOC

async def rpt_doc_manual(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    if update.message.text=="🔙 رجوع": await cmd_start(update,ctx); return ST_MAIN
    ctx.user_data.setdefault("R",{})["doctor_name"]=update.message.text.strip()
    return await _send_form(update.message,ctx)

async def _send_form(msg, ctx):
    await msg.reply_text(
        "📋 *أدخل بيانات المريض:*\n\n"
        "```\nالاسم: \nرقم الهوية: \nتاريخ الميلاد: \nرقم الجوال: \n"
        "جهة العمل: \nالجنسية: \nتاريخ بدء الإجازة: \nعدد الأيام: \n```\n\n"
        "📌 *مثال:*\n"
        "```\nالاسم: عبدالملك هاني عبدالشكور\nرقم الهوية: 1119717088\n"
        "تاريخ الميلاد: 01-01-1990\nرقم الجوال: 0501234567\n"
        "جهة العمل: شركة الوسيط\nالجنسية: سعودي\n"
        "تاريخ بدء الإجازة: 06-03-2026\nعدد الأيام: 1\n```",
        parse_mode="Markdown",reply_markup=KB_BACK)
    return ST_RPT_DATA

async def rpt_data(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    if update.message.text=="🔙 رجوع": await cmd_start(update,ctx); return ST_MAIN
    t=update.message.text
    def ex(pat): m=re.search(pat,t,re.MULTILINE); return m.group(1).strip() if m else ""
    name=ex(r'الاسم\s*[:：]\s*(.+)'); pid=ex(r'رقم الهوية\s*[:：]\s*(.+)')
    bd=ex(r'تاريخ الميلاد\s*[:：]\s*(.+)'); ph=ex(r'رقم الجوال\s*[:：]\s*(.+)')
    emp=ex(r'جهة العمل\s*[:：]\s*(.+)'); nat=ex(r'الجنسية\s*[:：]\s*(.+)')
    ld=ex(r'تاريخ بدء الإجازة\s*[:：]\s*(.+)'); days=ex(r'عدد الأيام\s*[:：]\s*(\d+)')
    miss=[]
    if not name: miss.append("الاسم")
    if not pid:  miss.append("رقم الهوية")
    if not ld:   miss.append("تاريخ بدء الإجازة")
    if not days: miss.append("عدد الأيام")
    if miss:
        await update.message.reply_text(
            "❌ *الحقول الناقصة:*\n"+"\n".join(f"  • {m}" for m in miss)+"\n\nأعد الإرسال:",
            parse_mode="Markdown"); return ST_RPT_DATA
    try: datetime.strptime(ld,"%d-%m-%Y")
    except: await update.message.reply_text("❌ تاريخ غير صحيح. الصيغة: DD-MM-YYYY"); return ST_RPT_DATA
    R=ctx.user_data.setdefault("R",{})
    R.update({"patient_name":name,"patient_id":pid,"birth_date":bd,"phone":ph,
              "employer":emp,"nationality":nat,"leave_date":ld,"days":days})
    de,_,_,_=_dur(ld,days)
    await update.message.reply_text(
        f"📋 *مراجعة البيانات:*\n━━━━━━━━━━━━━━━━━━\n"
        f"🏥 {R.get('hospital_name','')}\n👨‍⚕️ {R.get('doctor_name','')}\n"
        f"━━━━━━━━━━━━━━━━━━\n"
        f"👤 {name}\n🪪 {pid}\n📅 الميلاد: {bd or '—'}\n📱 {ph or '—'}\n"
        f"🏢 {emp or '—'}\n🌍 {nat or '—'}\n📅 {ld}\n🗓 {de}\n"
        f"━━━━━━━━━━━━━━━━━━\n💰 التكلفة: *{gs('report_price','10')} ريال*",
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup([
            [InlineKeyboardButton("✅ تأكيد الإصدار",   callback_data="RC_yes")],
            [InlineKeyboardButton("✏️ تعديل البيانات", callback_data="RC_edit")],
            [InlineKeyboardButton("❌ إلغاء",           callback_data="RC_no")],
        ])); return ST_RPT_CONF

async def rpt_confirm_cb(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    q=update.callback_query; u=q.from_user; await q.answer()
    if q.data=="RC_no":
        await q.edit_message_text("❌ تم الإلغاء.")
        await q.message.reply_text("🏠",reply_markup=KB(u.id)); ctx.user_data.clear(); return ST_MAIN
    if q.data=="RC_edit":
        await q.edit_message_text("✏️ أعد إرسال البيانات:"); return await _send_form(q.message,ctx)
    if q.data!="RC_yes": return ST_RPT_CONF
    price=float(gs("report_price","10")); bal=get_balance(u.id)
    if bal<price: await q.edit_message_text("❌ رصيدك غير كافٍ!"); return ST_MAIN
    wait_msg=await q.message.reply_text("⏳ *جاري إنشاء الإجازة... الرجاء الانتظار*",parse_mode="Markdown")
    R=ctx.user_data.get("R",{}); rnum=next_rnum()
    wu=gs("web_url","https://seha.sa"); vurl=f"{wu}/#/inquiries/slenquiry?code={rnum}"
    qp=await make_qr(rnum,vurl)
    logo_path=R.get("logo_path","")
    if not logo_path:
        hid=R.get("hospital_id",0)
        if hid:
            with _db() as _c:
                _hr=_c.execute("SELECT logo_path FROM hospitals WHERE id=?",(hid,)).fetchone()
                if _hr and _hr["logo_path"] and os.path.exists(_hr["logo_path"] or ""):
                    logo_path=_hr["logo_path"]
    # ترجمة async — عربي → إنجليزي بدقة عالية
    pname    = R.get("patient_name","")
    dname    = R.get("doctor_name","")
    hname    = R.get("hospital_name","")
    nat      = R.get("nationality","")
    emp      = R.get("employer","")

    await wait_msg.edit_text("⏳ *جاري ترجمة البيانات...*", parse_mode="Markdown")
    # ترجمة متوازية
    pname_en, dname_en, hname_en, nat_en, emp_en = await asyncio.gather(
        _translate_async(pname),
        _translate_async(dname),
        _translate_async(hname),
        _translate_async(nat),
        _translate_async(emp),
    )
    await wait_msg.edit_text("⏳ *جاري إنشاء الإجازة...*", parse_mode="Markdown")

    data={
        "patient_name":     pname,
        "patient_name_en":  pname_en,
        "patient_id":       R.get("patient_id",""),
        "nationality":      nat,
        "nationality_en":   nat_en,
        "employer":         emp,
        "employer_en":      emp_en,
        "leave_date":       R.get("leave_date",""),
        "days":             R.get("days","1"),
        "doctor_name":      dname,
        "doctor_name_en":   dname_en,
        "position_ar":      "\u0637\u0628\u064a\u0628 \u0639\u0627\u0645",
        "position_en":      "General",
        "hospital_name":    hname,
        "hospital_name_en": hname_en,
        "logo_path":        logo_path,
        "qr_path":          qp or "",
        "verify_url":       vurl,
    }
    try:
        pdf=await create_pdf_async(rnum,data)
    except Exception as e:
        logger.error(f"PDF: {e}",exc_info=True)
        await wait_msg.edit_text(f"❌ خطأ في إنشاء الإجازة: {e}")
        return ST_MAIN
    upd_balance(u.id,-price)
    with _db() as c:
        c.execute("""INSERT INTO reports
            (report_number,user_id,patient_name,patient_id,birth_date,phone,
             nationality,employer,city,leave_date,days,doctor_name,hospital_name,
             hospital_id,pdf_path,qr_path) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
            (rnum,u.id,R.get("patient_name"),R.get("patient_id"),R.get("birth_date",""),
             R.get("phone",""),R.get("nationality"),R.get("employer"),
             R.get("hospital_city",""),R.get("leave_date"),int(R.get("days","1")),
             R.get("doctor_name"),R.get("hospital_name"),R.get("hospital_id"),pdf,qp or "")); c.commit()
    await wait_msg.delete()
    try:
        with open(pdf,"rb") as f:
            await q.message.reply_document(f,filename=f"إجازة_{rnum}.pdf",
                caption=(f"✅ *تم إصدار الإجازة!*\n\n🔢 الرقم: `{rnum}`\n"
                         f"💰 الرصيد المتبقي: *{get_balance(u.id):.2f} ريال*"),
                parse_mode="Markdown")
    except Exception as e: await q.message.reply_text(f"❌ خطأ في إرسال الملف: {e}")
    for aid in ADMIN_IDS:
        try:
            await ctx.bot.send_message(aid,
                f"📋 *إجازة جديدة:* `{rnum}`\n👤 {R.get('patient_name','')}\n🏥 {R.get('hospital_name','')}",
                parse_mode="Markdown")
        except: pass
    await q.message.reply_text("🏠 القائمة الرئيسية:",reply_markup=KB(u.id))
    ctx.user_data.clear(); return ST_MAIN


