#  لوحة الإدارة
# ══════════════════════════════════════════════════════════════
async def adm_menu(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    u=update.effective_user
    if not is_admin(u.id): return ST_MAIN
    t=update.message.text
    if t in ["🔙 رجوع للرئيسية","🔙 رجوع"]: await cmd_start(update,ctx); return ST_MAIN

    elif t=="➕ إضافة مستشفى":
        await update.message.reply_text(
            "🏥 *إضافة مستشفى*\nأرسل: `اسم | مدينة | دكتور`\nمثال: `مستشفى الأمل | الرياض | أحمد`",
            parse_mode="Markdown",reply_markup=KB_ADM_BACK); return ST_ADM_HOSP1

    elif t=="➕ إضافة دكتور":
        hs=get_hospitals()
        if not hs: await update.message.reply_text("❌ لا توجد مستشفيات."); return ST_ADM
        items=[(h["id"],h["name"]) for h in hs]
        await update.message.reply_text("👨‍⚕️ اختر المستشفى:",reply_markup=ik_paged(items,"AD",0)); return ST_ADM_DOC1

    elif t=="💳 إنشاء كود شحن":
        await update.message.reply_text("💳 أدخل: `المبلغ | عدد الأكواد`\nمثال: `50 | 10`",
            parse_mode="Markdown",reply_markup=KB_ADM_BACK); return ST_ADM_CHARGE

    elif t=="🖼️ شعارات المستشفيات":
        hs=get_hospitals()
        if not hs: await update.message.reply_text("❌ لا توجد مستشفيات."); return ST_ADM
        items=[(h["id"],f"{'✅' if h['logo_path'] and os.path.exists(h['logo_path'] or '') else '⬜'} {h['name']}") for h in hs]
        await update.message.reply_text("🖼️ *شعارات المستشفيات*\n✅=لديه شعار | ⬜=بدون شعار",
            parse_mode="Markdown",reply_markup=ik_paged(items,"LG",0)); return ST_ADM_LOGO_SEL

    elif t=="🎨 إعدادات الخط":
        custom=gs("font_custom_path",""); fname=os.path.basename(custom) if custom else "NotoSansArabic (افتراضي)"
        await update.message.reply_text(
            f"🎨 *إعدادات الخط*\nالخط الحالي: `{fname}`",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([
                [InlineKeyboardButton("🔤 اختر خطاً",        callback_data="FS_font")],
                [InlineKeyboardButton("📤 رفع خط (.ttf)",    callback_data="FS_upload")],
                [InlineKeyboardButton("↩️ إعادة الافتراضي", callback_data="FS_reset")],
                [InlineKeyboardButton("🔙 رجوع",             callback_data="FS_back")],
            ])); return ST_ADM_FONT_SETTINGS

    elif t=="📊 الإحصائيات":
        with _db() as c:
            uc=c.execute("SELECT COUNT(*) as n FROM users").fetchone()["n"]
            rc=c.execute("SELECT COUNT(*) as n FROM reports").fetchone()["n"]
            hc=c.execute("SELECT COUNT(*) as n FROM hospitals WHERE is_active=1").fetchone()["n"]
            dc=c.execute("SELECT COUNT(*) as n FROM doctors WHERE is_active=1").fetchone()["n"]
            cu=c.execute("SELECT COUNT(*) as n FROM charge_codes WHERE is_used=1").fetchone()["n"]
            ct=c.execute("SELECT COUNT(*) as n FROM charge_codes").fetchone()["n"]
            rv=(c.execute("SELECT SUM(amount) as s FROM charge_codes WHERE is_used=1").fetchone()["s"] or 0)
        await update.message.reply_text(
            f"📊 *الإحصائيات:*\n━━━━━━━━━━━━━━━━━━\n"
            f"👥 المستخدمون: {uc}\n📋 الإجازات: {rc}\n"
            f"🏥 المستشفيات: {hc}\n👨‍⚕️ الأطباء: {dc}\n"
            f"💳 الأكواد: {cu}/{ct}\n💰 الإيرادات: {rv:.2f} ريال",
            parse_mode="Markdown"); return ST_ADM

    elif t=="👥 إدارة المستخدمين":
        with _db() as c:
            users=c.execute("SELECT telegram_id,full_name,balance,is_admin,is_banned FROM users ORDER BY id DESC LIMIT 20").fetchall()
        if not users: await update.message.reply_text("لا يوجد مستخدمون."); return ST_ADM
        btns=[]
        for uu in users:
            ic="🔴" if uu["is_banned"] else ("⭐" if uu["is_admin"] else "👤")
            btns.append([InlineKeyboardButton(f"{ic} {uu['full_name']} — {uu['balance']:.0f}ر",
                                               callback_data=f"UM_{uu['telegram_id']}")])
        btns.append([InlineKeyboardButton("🔙 رجوع",callback_data="UM_back")])
        await update.message.reply_text("👥 *المستخدمون:*",parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup(btns)); return ST_ADM_UACTION

    elif t=="⚙️ الإعدادات":
        price=gs("report_price","10"); sup=gs("support_whatsapp",""); web=gs("web_url","")
        maint="مفعّل ✅" if gs("bot_maintenance","0")=="1" else "معطّل ❌"
        await update.message.reply_text(
            f"⚙️ *الإعدادات:*\n━━━━━━━━━━━━━━━━━━\n"
            f"💊 السعر: {price} ريال\n📞 الدعم: {sup}\n🌐 الرابط: {web}\n🔧 الصيانة: {maint}",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([
                [InlineKeyboardButton("💊 تغيير السعر",   callback_data="CFG_price")],
                [InlineKeyboardButton("📞 تغيير الدعم",   callback_data="CFG_sup")],
                [InlineKeyboardButton("🌐 تغيير الرابط",  callback_data="CFG_web")],
                [InlineKeyboardButton("🔧 تبديل الصيانة", callback_data="CFG_maint")],
                [InlineKeyboardButton("🔙 رجوع",          callback_data="CFG_back")],
            ])); return ST_ADM

    elif t=="📢 إرسال إعلان":
        await update.message.reply_text("📢 أدخل نص الإعلان:",reply_markup=KB_ADM_BACK); return ST_ADM_BCAST

    elif t=="📋 سجل الأخطاء":
        try:
            with open(LOG_PATH,"r",encoding="utf-8") as f: lines=f.readlines()
            last="".join(lines[-25:]) if len(lines)>25 else "".join(lines)
            if not last: last="لا توجد أخطاء."
            if len(last)>3900: last="...\n"+last[-3900:]
            await update.message.reply_text(f"```\n{last}\n```",parse_mode="Markdown")
        except Exception as e: await update.message.reply_text(f"❌ {e}")
        return ST_ADM
    return ST_ADM


# ══════════════════════════════════════════════════════════════
#  معالجات الإدارة
# ══════════════════════════════════════════════════════════════
async def adm_hosp1(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    t=update.message.text
    if t in ["🔙 رجوع","🔙 رجوع للإدارة"]:
        await update.message.reply_text("👨‍💼",reply_markup=KB_ADM); return ST_ADM
    parts=[p.strip() for p in t.split("|")]
    if len(parts)<2: await update.message.reply_text("❌ الصيغة: `اسم | مدينة | دكتور`",parse_mode="Markdown"); return ST_ADM_HOSP1
    name=parts[0]; city=parts[1] if len(parts)>1 else ""; doctor=parts[2] if len(parts)>2 else ""
    with _db() as c:
        cur=c.execute("INSERT INTO hospitals (name,name_ar,city,license_number) VALUES (?,?,?,?)",(name,name,city,""))
        hid=cur.lastrowid
        if doctor: c.execute("INSERT INTO doctors (hospital_id,name,name_ar) VALUES (?,?,?)",(hid,doctor,doctor))
        c.commit()
    await update.message.reply_text(
        f"✅ *تم إضافة المستشفى!*\n🏥 {name}\n🌆 {city}"+(f"\n👨‍⚕️ {doctor}" if doctor else ""),
        parse_mode="Markdown",reply_markup=KB_ADM); return ST_ADM

async def adm_doc1(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    q=update.callback_query; await q.answer()
    if q.data=="AD_back": await q.edit_message_text("🔙"); return ST_ADM
    if q.data.startswith("AD_pg_"):
        page=int(q.data.split("_")[-1]); hs=get_hospitals(); items=[(h["id"],h["name"]) for h in hs]
        await q.edit_message_text("👨‍⚕️ اختر المستشفى:",reply_markup=ik_paged(items,"AD",page)); return ST_ADM_DOC1
    hid=int(q.data[3:]); ctx.user_data["ADH"]=hid
    with _db() as c: h=c.execute("SELECT name FROM hospitals WHERE id=?",(hid,)).fetchone()
    await q.edit_message_text(f"👨‍⚕️ إضافة دكتور لـ {h['name'] if h else '؟'}\n\nأدخل الاسم:"); return ST_ADM_DOC2

async def adm_doc2(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    if update.message.text in ["🔙 رجوع","🔙 رجوع للإدارة"]:
        await update.message.reply_text("👨‍💼",reply_markup=KB_ADM); return ST_ADM
    name=update.message.text.strip(); hid=ctx.user_data.get("ADH",1)
    with _db() as c:
        c.execute("INSERT INTO doctors (hospital_id,name,name_ar) VALUES (?,?,?)",(hid,name,name)); c.commit()
    await update.message.reply_text(f"✅ *تم إضافة الدكتور:* {name}",parse_mode="Markdown",reply_markup=KB_ADM)
    return ST_ADM

async def adm_charge(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    if update.message.text in ["🔙 رجوع","🔙 رجوع للإدارة"]:
        await update.message.reply_text("👨‍💼",reply_markup=KB_ADM); return ST_ADM
    try:
        parts=[p.strip() for p in update.message.text.split("|")]
        amount=float(parts[0]); count=min(int(parts[1]) if len(parts)>1 else 1,100)
        codes=[]
        with _db() as c:
            for _ in range(count):
                code="".join(random.choices(string.ascii_uppercase+string.digits,k=10))
                c.execute("INSERT OR IGNORE INTO charge_codes (code,amount) VALUES (?,?)",(code,amount))
                codes.append(code)
            c.commit()
        txt=f"✅ *{count} كود بقيمة {amount:.0f} ريال:*\n\n"+"\n".join(f"`{c}`" for c in codes)
        if len(txt)>4000: txt=txt[:4000]+"..."
        await update.message.reply_text(txt,parse_mode="Markdown",reply_markup=KB_ADM)
    except Exception as e: await update.message.reply_text(f"❌ خطأ: {e}")
    return ST_ADM

async def adm_uaction(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    q=update.callback_query; await q.answer(); d=q.data
    if d=="UM_back": await q.edit_message_text("↩️"); return ST_ADM
    if d.startswith("UM_"):
        uid=int(d[3:])
        with _db() as c: uu=c.execute("SELECT * FROM users WHERE telegram_id=?",(uid,)).fetchone()
        if not uu: await q.edit_message_text("❌ مستخدم غير موجود."); return ST_ADM
        st="محظور 🔴" if uu["is_banned"] else ("أدمن ⭐" if uu["is_admin"] else "عادي 👤")
        await q.edit_message_text(
            f"👤 *{uu['full_name']}*\n🆔 {uid}\n💰 {uu['balance']:.2f} ريال\nالحالة: {st}",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([
                [InlineKeyboardButton("💰 إضافة رصيد",   callback_data=f"UA_add_{uid}")],
                [InlineKeyboardButton("🔴 حظر/رفع",      callback_data=f"UA_ban_{uid}")],
                [InlineKeyboardButton("⭐ منح/سحب أدمن", callback_data=f"UA_adm_{uid}")],
                [InlineKeyboardButton("🔙 رجوع",          callback_data="UM_back")],
            ])); return ST_ADM_UACTION
    if d.startswith("UA_"):
        parts=d.split("_"); action=parts[1]; uid=int(parts[2])
        with _db() as c:
            if action=="ban":
                uu=c.execute("SELECT is_banned FROM users WHERE telegram_id=?",(uid,)).fetchone()
                new=0 if uu and uu["is_banned"] else 1
                c.execute("UPDATE users SET is_banned=? WHERE telegram_id=?",(new,uid)); c.commit()
                await q.edit_message_text(f"{'✅ رُفع الحظر' if not new else '🔴 تم الحظر'}")
            elif action=="adm":
                uu=c.execute("SELECT is_admin FROM users WHERE telegram_id=?",(uid,)).fetchone()
                new=0 if uu and uu["is_admin"] else 1
                c.execute("UPDATE users SET is_admin=? WHERE telegram_id=?",(new,uid)); c.commit()
                await q.edit_message_text(f"{'✅ منح أدمن' if new else '✅ سُحب أدمن'}")
            elif action=="add":
                ctx.user_data["ADD_BAL_UID"]=uid
                await q.edit_message_text("💰 أدخل المبلغ:"); return ST_ADM_ADDBAL
        return ST_ADM
    return ST_ADM

async def adm_addbal(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    if update.message.text in ["🔙 رجوع","🔙 رجوع للإدارة"]:
        await update.message.reply_text("👨‍💼",reply_markup=KB_ADM); return ST_ADM
    try:
        amount=float(update.message.text.strip()); uid=ctx.user_data.get("ADD_BAL_UID")
        if uid: upd_balance(uid,amount)
        await update.message.reply_text(f"✅ تمت إضافة *{amount:.2f} ريال* لـ `{uid}`",
            parse_mode="Markdown",reply_markup=KB_ADM)
    except: await update.message.reply_text("❌ أدخل رقماً."); return ST_ADM_ADDBAL
    return ST_ADM

async def adm_cfg_cb(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    q=update.callback_query; await q.answer(); d=q.data
    if d=="CFG_back": await q.edit_message_text("↩️"); return ST_ADM
    if d=="CFG_maint":
        cur=gs("bot_maintenance","0"); ss("bot_maintenance","0" if cur=="1" else "1")
        await q.edit_message_text(f"🔧 الصيانة: {'مفعّلة ✅' if cur=='0' else 'معطّلة ❌'}"); return ST_ADM
    prompts={"CFG_price":("report_price","💊 أدخل السعر:"),
             "CFG_sup":  ("support_whatsapp","📞 أدخل رقم الواتساب:"),
             "CFG_web":  ("web_url","🌐 أدخل رابط الموقع:")}
    if d in prompts:
        ctx.user_data["CFG_KEY"]=prompts[d][0]
        await q.edit_message_text(prompts[d][1]); return ST_ADM_PRICE
    return ST_ADM

async def adm_price(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    if update.message.text in ["🔙 رجوع","🔙 رجوع للإدارة"]:
        await update.message.reply_text("👨‍💼",reply_markup=KB_ADM); return ST_ADM
    key=ctx.user_data.get("CFG_KEY","report_price")
    ss(key,update.message.text.strip())
    await update.message.reply_text(f"✅ تم حفظ: `{update.message.text.strip()}`",
        parse_mode="Markdown",reply_markup=KB_ADM); return ST_ADM

async def adm_bcast(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    if update.message.text in ["🔙 رجوع","🔙 رجوع للإدارة"]:
        await update.message.reply_text("👨‍💼",reply_markup=KB_ADM); return ST_ADM
    with _db() as c: users=c.execute("SELECT telegram_id FROM users WHERE is_banned=0").fetchall()
    sent=failed=0; msg=await update.message.reply_text(f"📢 جاري الإرسال لـ {len(users)} مستخدم...")
    for uu in users:
        try: await ctx.bot.send_message(uu["telegram_id"],f"📢 *إعلان:*\n\n{update.message.text}",parse_mode="Markdown"); sent+=1
        except: failed+=1
        await asyncio.sleep(0.05)
    await msg.edit_text(f"✅ اكتمل: تم {sent} | فشل {failed}"); return ST_ADM


