#  شعارات المستشفيات
# ══════════════════════════════════════════════════════════════
async def adm_logo_sel(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    q=update.callback_query; await q.answer(); d=q.data
    if d=="LG_back": await q.edit_message_text("↩️"); return ST_ADM
    if d.startswith("LG_pg_"):
        page=int(d.split("_")[-1]); hs=get_hospitals()
        items=[(h["id"],f"{'✅' if h['logo_path'] and os.path.exists(h['logo_path'] or '') else '⬜'} {h['name']}") for h in hs]
        await q.edit_message_text("🖼️ اختر مستشفى:",reply_markup=ik_paged(items,"LG",page)); return ST_ADM_LOGO_SEL
    if d.startswith("LG_"):
        hid=int(d[3:])
        with _db() as c: h=c.execute("SELECT * FROM hospitals WHERE id=?",(hid,)).fetchone()
        if not h: await q.edit_message_text("❌"); return ST_ADM
        ctx.user_data["LOGO_HID"]=hid
        logo_ok=h["logo_path"] and os.path.exists(h["logo_path"] or "")
        await q.edit_message_text(
            f"🏥 *{h['name']}*\n{'✅ لديه شعار' if logo_ok else '⬜ بدون شعار'}",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([
                [InlineKeyboardButton("📤 رفع/تغيير الشعار",callback_data=f"LGA_up_{hid}")],
                [InlineKeyboardButton("🗑️ حذف الشعار",      callback_data=f"LGA_del_{hid}")],
                [InlineKeyboardButton("👁️ معاينة",          callback_data=f"LGA_pre_{hid}")],
                [InlineKeyboardButton("🔙 رجوع",            callback_data="LG_back")],
            ])); return ST_ADM_LOGO_SEL
    if d.startswith("LGA_up_"):
        hid=int(d.split("_")[-1]); ctx.user_data["LOGO_HID"]=hid
        await q.edit_message_text("📤 أرسل صورة الشعار (PNG/JPG)\n📌 يُفضل PNG بخلفية شفافة\n📐 مثالي: 300×300")
        return ST_ADM_LOGO_UP
    if d.startswith("LGA_del_"):
        hid=int(d.split("_")[-1])
        with _db() as c:
            old=c.execute("SELECT logo_path FROM hospitals WHERE id=?",(hid,)).fetchone()
            if old and old["logo_path"]:
                try: os.remove(old["logo_path"])
                except: pass
            c.execute("UPDATE hospitals SET logo_path=NULL WHERE id=?",(hid,)); c.commit()
        await q.edit_message_text("✅ تم حذف الشعار."); return ST_ADM
    if d.startswith("LGA_pre_"):
        hid=int(d.split("_")[-1])
        with _db() as c: h=c.execute("SELECT * FROM hospitals WHERE id=?",(hid,)).fetchone()
        if not h or not h["logo_path"] or not os.path.exists(h["logo_path"] or ""):
            await q.edit_message_text("❌ لا يوجد شعار."); return ST_ADM
        try:
            buf=await preview_async(h["logo_path"])
            await q.message.reply_photo(buf,caption=f"👁️ معاينة: {h['name']}")
        except Exception as e: await q.edit_message_text(f"❌ {e}")
        return ST_ADM
    return ST_ADM_LOGO_SEL

async def adm_logo_up(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    msg=update.message
    if not is_admin(msg.from_user.id): return ST_ADM
    if msg.text and msg.text in ["🔙 رجوع للإدارة","🔙 رجوع"]:
        await msg.reply_text("↩️",reply_markup=KB_ADM); return ST_ADM
    hid=ctx.user_data.get("LOGO_HID")
    if not hid: await msg.reply_text("❌ لم يُحدد مستشفى.",reply_markup=KB_ADM); return ST_ADM
    file_obj=None
    if msg.photo: file_obj=await msg.photo[-1].get_file()
    elif msg.document and msg.document.mime_type in ("image/png","image/jpeg","image/jpg"):
        file_obj=await msg.document.get_file()
    if not file_obj:
        await msg.reply_text("❌ أرسل صورة PNG أو JPEG.",reply_markup=KB_ADM_BACK); return ST_ADM_LOGO_UP
    try:
        buf=BytesIO(); await file_obj.download_to_memory(buf); buf.seek(0)
        os.makedirs(LOGOS_DIR,exist_ok=True)
        logo_path=os.path.join(LOGOS_DIR,f"hospital_{hid}.png")
        Image.open(buf).convert("RGBA").save(logo_path,"PNG")
        with _db() as c: c.execute("UPDATE hospitals SET logo_path=? WHERE id=?",(logo_path,hid)); c.commit()
        with _db() as c: h=c.execute("SELECT name FROM hospitals WHERE id=?",(hid,)).fetchone()
        await msg.reply_text(
            f"✅ *تم رفع الشعار!*\n🏥 {h['name'] if h else hid}\n\n"
            f"💡 لمعاينة الشعار اضغط 👁️ معاينة من قائمة الشعارات",
            parse_mode="Markdown",reply_markup=KB_ADM)
        ctx.user_data.pop("LOGO_HID",None); return ST_ADM
    except Exception as e:
        logger.error(f"Logo: {e}",exc_info=True)
        await msg.reply_text(f"❌ خطأ: {e}",reply_markup=KB_ADM_BACK); return ST_ADM_LOGO_UP

# ══════════════════════════════════════════════════════════════
#  إعدادات الخط
# ══════════════════════════════════════════════════════════════
async def adm_font_cb(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    q=update.callback_query; await q.answer(); d=q.data
    if not is_admin(q.from_user.id): return ST_ADM
    if d=="FS_back": await q.edit_message_text("↩️"); return ST_ADM
    if d=="FS_reset":
        ss("font_custom_path",""); _FC.clear()
        await q.edit_message_text("✅ تم إعادة الخط الافتراضي (NotoSansArabic)."); return ST_ADM
    if d=="FS_font":
        fonts=_list_fonts()
        btns=[[InlineKeyboardButton(name,callback_data=f"FS_sf_{i}")] for i,(name,_) in enumerate(fonts)]
        btns.append([InlineKeyboardButton("🔙 رجوع",callback_data="FS_back")])
        await q.edit_message_text("🔤 *اختر نوع الخط:*",parse_mode="Markdown",reply_markup=InlineKeyboardMarkup(btns))
        ctx.user_data["FONTS_LIST"]=fonts; return ST_ADM_FONT_SETTINGS
    if d.startswith("FS_sf_"):
        idx=int(d[6:]); fonts=ctx.user_data.get("FONTS_LIST",_list_fonts())
        if 0<=idx<len(fonts):
            name,path=fonts[idx]; ss("font_custom_path",path); _FC.clear()
            await q.edit_message_text(f"✅ تم اختيار: *{name}*",parse_mode="Markdown")
        return ST_ADM
    if d=="FS_upload":
        await q.edit_message_text("📤 أرسل ملف الخط (.ttf)")
        ctx.user_data["AWAITING_FONT"]=True; return ST_ADM_FONT_UPLOAD
    return ST_ADM_FONT_SETTINGS

async def adm_font_upload(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    msg=update.message
    if not is_admin(msg.from_user.id): return ST_ADM
    if msg.text and msg.text in ["🔙 رجوع","🔙 رجوع للإدارة"]:
        ctx.user_data.pop("AWAITING_FONT",None); await msg.reply_text("↩️",reply_markup=KB_ADM); return ST_ADM
    if not msg.document: await msg.reply_text("❌ أرسل ملف .ttf"); return ST_ADM_FONT_UPLOAD
    if not msg.document.file_name.lower().endswith(".ttf"):
        await msg.reply_text("❌ الملف يجب أن يكون .ttf"); return ST_ADM_FONT_UPLOAD
    try:
        os.makedirs(FONTS_DIR,exist_ok=True)
        font_path=os.path.join(FONTS_DIR,msg.document.file_name)
        file_obj=await msg.document.get_file(); await file_obj.download_to_drive(font_path)
        ImageFont.truetype(font_path,16)
        ss("font_custom_path",font_path); _FC.clear()
        await msg.reply_text(f"✅ تم رفع الخط: `{msg.document.file_name}`",parse_mode="Markdown",reply_markup=KB_ADM)
        ctx.user_data.pop("AWAITING_FONT",None); return ST_ADM
    except Exception as e:
        await msg.reply_text(f"❌ خطأ: {e}"); return ST_ADM_FONT_UPLOAD

# ══════════════════════════════════════════════════════════════
#  معالج الأخطاء + أوامر الأدمن
# ══════════════════════════════════════════════════════════════
async def err_handler(update, ctx: ContextTypes.DEFAULT_TYPE):
    logger.error(f"ERROR: {ctx.error}",exc_info=ctx.error)

async def cmd_setprice(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    if not is_admin(update.effective_user.id): return
    try: p=float(ctx.args[0]); ss("report_price",p); await update.message.reply_text(f"✅ السعر: {p} ريال")
    except: await update.message.reply_text("الاستخدام: /setprice 10")

async def cmd_addbal(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    if not is_admin(update.effective_user.id): return
    try:
        uid=int(ctx.args[0]); amt=float(ctx.args[1]); upd_balance(uid,amt)
        await update.message.reply_text(f"✅ تمت إضافة {amt} ريال لـ {uid}")
    except: await update.message.reply_text("الاستخدام: /addbalance USER_ID AMOUNT")

async def cmd_stats(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    if not is_admin(update.effective_user.id): return
    with _db() as c:
        u=c.execute("SELECT COUNT(*) as n FROM users").fetchone()["n"]
        r=c.execute("SELECT COUNT(*) as n FROM reports").fetchone()["n"]
    await update.message.reply_text(f"📊 مستخدمون: {u} | إجازات: {r}")


# ══════════════════════════════════════════════════════════════
#  Main
# ══════════════════════════════════════════════════════════════
def main():
    init_db()
    app = Application.builder().token(BOT_TOKEN).build()
    conv = ConversationHandler(
        entry_points=[CommandHandler("start", cmd_start)],
        states={
            ST_MAIN:            [MessageHandler(filters.TEXT&~filters.COMMAND, main_menu)],
            ST_RPT_SEARCH:      [CallbackQueryHandler(rpt_search_cb)],
            ST_RPT_SINPUT:      [MessageHandler(filters.TEXT&~filters.COMMAND, rpt_sinput)],
            ST_RPT_CITY:        [CallbackQueryHandler(rpt_search_cb)],
            ST_RPT_HOSP:        [CallbackQueryHandler(rpt_hosp_cb)],
            ST_RPT_DOC:         [CallbackQueryHandler(rpt_doc_cb)],
            ST_RPT_DOC_MAN:     [MessageHandler(filters.TEXT&~filters.COMMAND, rpt_doc_manual)],
            ST_RPT_DATA:        [MessageHandler(filters.TEXT&~filters.COMMAND, rpt_data)],
            ST_RPT_CONF:        [CallbackQueryHandler(rpt_confirm_cb)],
            ST_CHARGE:          [MessageHandler(filters.TEXT&~filters.COMMAND, do_charge)],
            ST_ADM:             [MessageHandler(filters.TEXT&~filters.COMMAND, adm_menu),
                                 CallbackQueryHandler(adm_cfg_cb,  pattern=r"^CFG_"),
                                 CallbackQueryHandler(adm_uaction, pattern=r"^(UM_|UA_)")],
            ST_ADM_HOSP1:       [MessageHandler(filters.TEXT&~filters.COMMAND, adm_hosp1)],
            ST_ADM_DOC1:        [CallbackQueryHandler(adm_doc1)],
            ST_ADM_DOC2:        [MessageHandler(filters.TEXT&~filters.COMMAND, adm_doc2)],
            ST_ADM_CHARGE:      [MessageHandler(filters.TEXT&~filters.COMMAND, adm_charge)],
            ST_ADM_BCAST:       [MessageHandler(filters.TEXT&~filters.COMMAND, adm_bcast)],
            ST_ADM_PRICE:       [MessageHandler(filters.TEXT&~filters.COMMAND, adm_price)],
            ST_ADM_UACTION:     [CallbackQueryHandler(adm_uaction)],
            ST_ADM_ADDBAL:      [MessageHandler(filters.TEXT&~filters.COMMAND, adm_addbal)],
            ST_ADM_LOGO_SEL:    [CallbackQueryHandler(adm_logo_sel)],
            ST_ADM_LOGO_UP:     [MessageHandler(
                (filters.PHOTO|filters.Document.IMAGE|filters.TEXT)&~filters.COMMAND, adm_logo_up)],
            ST_ADM_FONT_SETTINGS:[CallbackQueryHandler(adm_font_cb, pattern=r"^FS_")],
            ST_ADM_FONT_UPLOAD:  [MessageHandler(
                (filters.Document.ALL|filters.TEXT)&~filters.COMMAND, adm_font_upload)],
        },
        fallbacks=[CommandHandler("start", cmd_start)],
        allow_reentry=True,
        per_message=False,
    )
    app.add_handler(conv)
    app.add_handler(CommandHandler("setprice",   cmd_setprice))
    app.add_handler(CommandHandler("addbalance", cmd_addbal))
    app.add_handler(CommandHandler("stats",      cmd_stats))
    app.add_error_handler(err_handler)
    logger.info("🚀 البوت يعمل — v12 Final")
    app.run_polling(drop_pending_updates=True)

if __name__ == "__main__":
    main()
